vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vUv = 0.5 + (1.0 - abs( fract( vUv * 0.5 ) * 2 - 1.0 )-.5); // Eo.S. mirror code
vec2 noise = (texture(sampler_noise_lq,vUv*8+rand_frame.xy)-0.5);
vUv += 0.005*noise;
ret = mix(GetPixel(vUv), GetBlur1(vUv),0);
vUv = (vUv+vUvOriginal)/2;
ret += mix(GetPixel(vUv), GetBlur1(vUv),0);

vec3 scale = slow_roam_cos;
scale = scale / max(max(scale.x,scale.y), scale.z);
scale = mix(scale,1,0.7) ;
ret = ret * 0.45 * scale  - 0.004 ;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // Langit dengan menggunakan garis warna
    line_color1 = vec3(0, 0, 0.0);
    line_color2 = vec3(0.4, 0.2, 0.0);

    float blend_factor = smoothstep(0.4, 0.6, vUv.y);
    color = mix(line_color1, line_color2, blend_factor);

    // Bintang kecil-kecil
    uv1.y = vUv.y;
    uv1.x = vUv.x;
    uv1 = 1.0*(uv1);

    uv_star_movement = fract(uv1+q3*vec2(1,0.0)) ;
    vec2 star_uv = uv_star_movement * 130.0; // Tingkatkan untuk mendapatkan lebih banyak bintang
    vec2 star_id = floor(star_uv);
    vec2 star_frag = fract(star_uv);

    // Kecerahan bintang acak
    float random = fract(sin(dot(star_id, vec2(12.9898, 78.233))) * 43758.5453);
    float star_brightness = step(0.990, random)*random;

    color += star_brightness*smoothstep(0.5, 0.0, length(star_frag - 0.5));

    glow = texture(sampler_main, vUv).xyz*1 +
                 GetBlur1(vUv)*0 +
                 GetBlur2(vUv)*0 +
                 GetBlur3(vUv)*0 +
                 0;
    glow += GetBlur2((vUv-0.5)*0.999 + 0.5);
    glow *= 1;

    ret = vec4(color + glow, 1.0);

  fragColor = ret;
}
